// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>
#define MAX 200
int dp[MAX][MAX];
int nums[MAX];
char ops[MAX];
int maxVal(int i, int j) {
    if (i == j) return nums[i];
    if (dp[i][j] != -1) return dp[i][j];
    int max = -1e9;
    for (int k = i; k < j; k++) {
        int left = maxVal(i, k);
        int right = maxVal(k + 1, j);
        if (ops[k] == '+') max = max > left + right ? max : left + right;
        else max = max > left - right ? max : left - right;
    }
    return dp[i][j] = max;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        for (int i = 0; i < N; i++) scanf("%d", &nums[i]);
        for (int i = 0; i < N - 1; i++) scanf(" %c", &ops[i]);
        memset(dp, -1, sizeof(dp));
        printf("%d\n", maxVal(0, N - 1));
    }
    return 0;
}

