// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    static final int MAX = 200;
    static int[][] dp = new int[MAX][MAX];
    static int[] nums = new int[MAX];
    static char[] ops = new char[MAX];
    public static int maxVal(int i, int j) {
        if (i == j) return nums[i];
        if (dp[i][j] != -1) return dp[i][j];
        int max = -1000000000;
        for (int k = i; k < j; k++) {
            int left = maxVal(i, k);
            int right = maxVal(k + 1, j);
            if (ops[k] == '+') max = Math.max(max, left + right);
            else max = Math.max(max, left - right);
        }
        return dp[i][j] = max;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            for (int i = 0; i < N; i++) nums[i] = sc.nextInt();
            for (int i = 0; i < N - 1; i++) ops[i] = sc.next().charAt(0);
            for (int i = 0; i < MAX; i++) {
                for (int j = 0; j < MAX; j++) {
                    dp[i][j] = -1;
                }
            }
            System.out.println(maxVal(0, N - 1));
        }
    }
}

